mapper.select:

             and recpt_id = #{recptId}
     and item_id = #{itemId}
     and item_code like concat('%', #{itemCode}, '%')
     and item_name like concat('%', #{itemName}, '%')
     and specification like concat('%', #{specification}, '%')
     and unit_of_measure like concat('%', #{unitOfMeasure}, '%')
     and unit_name like concat('%', #{unitName}, '%')
     and unit2 like concat('%', #{unit2}, '%')
     and unit2_name like concat('%', #{unit2Name}, '%')
     and batch_id = #{batchId}
     and batch_code like concat('%', #{batchCode}, '%')
     and warehouse_id = #{warehouseId}
     and warehouse_code like concat('%', #{warehouseCode}, '%')
     and warehouse_name like concat('%', #{warehouseName}, '%')
     and location_id = #{locationId}
     and area_id = #{areaId}
     and notice_line_id = #{noticeLineId}
     and create_by like concat('%', #{createBy}, '%')
     and update_by like concat('%', #{updateBy}, '%')

order by create_time desc
